#include <iostream>
using namespace std;

class Complex {
public:
    int r, i;
    Complex(int r = 0, int i = 0) : r(r), i(i) {}

    // Overloading +
    Complex operator + (Complex const &obj) {
        Complex res;
        res.r = r + obj.r;
        res.i = i + obj.i;
        return res;
    }
};

int main() {
    Complex c1(10, 5), c2(2, 4);
    Complex c3 = c1 + c2;
    cout << c3.r << " + " << c3.i << "i" << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Shape {
public:
    virtual void draw() { cout << "Drawing Shape\n"; }
};

class Circle : public Shape {
public:
    void draw() override { cout << "Drawing Circle\n"; }
};

int main() {
    Shape *s = new Circle();
    s->draw(); // Calls Circle's draw
    return 0;
}

